def cpf_valido(cpf):
    cpf = ''.join(c for c in cpf if c.isdigit())
    if len(cpf) != 11 or cpf == cpf[0]*11:
        return False
    soma = sum(int(cpf[i]) * (10-i) for i in range(9))
    d1 = (soma * 10 % 11) % 10
    if d1 != int(cpf[9]):
        return False
    soma = sum(int(cpf[i]) * (11-i) for i in range(10))
    d2 = (soma * 10 % 11) % 10
    return d2 == int(cpf[10])

