def multiplicar_matrizes(A, B):
    linhas_A, colunas_A = len(A), len(A[0])
    colunas_B = len(B[0])
    resultado = [[0] * colunas_B for _ in range(linhas_A)]
    for i in range(linhas_A):
        for j in range(colunas_B):
