def tamanho_diretorio(caminho):
    total = 0
    for raiz, _, arquivos in os.walk(caminho):
        for arquivo in arquivos:
            total += os.path.getsize(os.path.join(raiz, arquivo))
    return total

def raiz_quadrada(n, precisao=1e-10):
    if n < 0:
        raise ValueError('Numero negativo')
    if n == 0:
        return 0
    x = n
    while True:
        raiz = (x + n / x) / 2
        if abs(raiz - x) < precisao:
            return raiz
        x = raiz

